<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;class WorkspaceSetting extends Model{protected $fillable=['workspace_id','company_name','logo_path','timezone','currency','working_days','office_start_time','office_end_time','daily_report_deadline','daily_report_required','proof_required_by_default','ai_enabled','notification_settings','feature_flags'];protected function casts():array{return ['working_days'=>'array','daily_report_required'=>'boolean','proof_required_by_default'=>'boolean','ai_enabled'=>'boolean','notification_settings'=>'array','feature_flags'=>'array'];}public function workspace(){return $this->belongsTo(Workspace::class);}}
